package com.evolua.auth.infrastructure.security; import io.jsonwebtoken.Jwts; import io.jsonwebtoken.security.Keys; import java.nio.charset.StandardCharsets; import java.time.Instant; import java.util.Date; import java.util.List; import javax.crypto.SecretKey; import org.springframework.beans.factory.annotation.Value; import org.springframework.stereotype.Component; @Component public class TokenIssuer { private final SecretKey key; public TokenIssuer(@Value("${app.security.jwt.secret}") String secret) { this.key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8)); } public String accessToken(String userId, String email, List<String> roles) { Instant now = Instant.now(); return Jwts.builder().subject(userId).claim("email", email).claim("roles", roles).issuedAt(Date.from(now)).expiration(Date.from(now.plusSeconds(1800))).signWith(key).compact(); } public String refreshToken(String userId, String email, List<String> roles) { Instant now = Instant.now(); return Jwts.builder().subject(userId).claim("email", email).claim("roles", roles).issuedAt(Date.from(now)).expiration(Date.from(now.plusSeconds(2592000))).signWith(key).compact(); } }
